import React, { useState, useEffect } from "react";
import axios from "axios";

// import Paypal from "./Paypal";
const App = () => {
  const [scriptLoaded, setScriptLoaded] = useState(false);
  const [buttonLoaded, setButtonLoaded] = useState(false);
  const [payload, setPayload] = useState({
    tenantId: "",
    organizationId: "",
    invoiceId: "",
    vendorId: "",
    version: "",
    amount: "12",
    email: "",
    paypalEmail: "sb-bymml6171154@business.example.com",
    paymentType: "",
    currencyType: "",
    paymentBy: "",
    currencyCode: "USD",
    balanceDue: "",
    paymentMethod: "",
    transactionFee: "0",
    merchantId: "",
    clientId: "",
    Token: "",
  });

  //Get Url Params
  const getParameterByName = (name, url) => {
    if (!url) url = window.location.href;
    name = name.replace(/[\[\]]/g, "\\$&");
    var regex = new RegExp("[?&]" + name + "(=([^&#]*)|&|#|$)");
    var results = regex.exec(url);
    if (!results) return null;
    if (!results[2]) return "";
    return decodeURIComponent(results[2].replace(/\+/g, " "));
  };

  useEffect(() => {
    let urlPayload = getParameterByName("payload");
    let uPayload = JSON.parse(urlPayload);
    if (uPayload) {
      uPayload.paypalEmail && setPayload(uPayload);
    let { merchantId, clientId } = uPayload;
    if (merchantId && clientId) {
      let src = `https://www.paypal.com/sdk/js?&client-id=${clientId}&merchant-id=${merchantId}`;
      const script = document.createElement("script");
      script.async = true;
      script.src = src;
      document.getElementById("body").prepend(script);
      setScriptLoaded(true);
      console.log("Loaded");
    }
  }
  }, []);

  useEffect(() => {
    if (scriptLoaded) {
      setButtonLoaded(false);
      axios({
        method: "get",
        url: `${process.env.REACT_APP_LDOCS_API_URL}/payment/requestAccessTokenPaypal`,
      }).then((response) => {
        let accessToken = response.data.access_token;
        window.paypal
          .Buttons({
            createOrder: function (data, actions) {
              return axios({
                method: "post",
                url: `${process.env.REACT_APP_LDOCS_API_URL}/payment/my-server/create-order`,
                data: {
                  access_token: accessToken,
                  purchase_units: [
                    {
                      amount: {
                        currency_code: payload.currencyCode,
                        value: payload.amount,
                      },
                      payee: {
                        email_address: payload.paypalEmail,
                        // email_address:'jehanxaibahmed@gmail.com',
                      },
                      payment_instruction: {
                        disbursement_mode: "INSTANT",
                        platform_fees: [
                          {
                            amount: {
                              currency_code: payload.currencyCode,
                              value: 1.0,
                            },
                          },
                        ],
                      },
                    },
                  ],
                },
                headers: {
                  "Content-Type": "application/json",
                  cooljwt: payload.Token,
                },
              })
                .then(function (res) {
                  return res;
                })
                .then(function (data) {
                  return data.data.id.id;
                });
            },
            onApprove: function (data, actions) {
              setButtonLoaded(false);
              return axios({
                method: "post",
                url: `${process.env.REACT_APP_LDOCS_API_URL}/payment/my-server/handle-approve/${data.orderID}`,
                data: {
                  access_token: accessToken,
                },
                headers: {
                  "Content-Type": "application/json",
                  cooljwt: payload.Token,
                },
              }).then(function (res) {
                if (!res.ok) {
                  console.log(res);
                  let response = res.data.result;
                  let payer = response.payer;
                  let purchase_units = response.purchase_units;
                  let status = response.status;
                  let transaction = purchase_units[0].payments.captures[0];
                  let orderId = response.id;
                  let payerEmail = payer.email_address;
                  let payerId = payer.payer_id;
                  let data = {
                    tenantId: payload.tenantId,
                    organizationId: payload.organizationId,
                    invoiceId: payload.invoiceId,
                    vendorId: payload.vendorId,
                    version: payload.version,
                    paidAmount: payload.amount,
                    updatedBy: payload.email,
                    paymentID: transaction.id,
                    payerID: payerId,
                    paymentType: payload.paymentType,
                    currencyType: payload.currencyType,
                    orderId: orderId,
                    paymentGateway: payload.paymentBy,
                    currencyCode: payload.currencyCode,
                    balanceDue: payload.balanceDue,
                    paymentMethod: payload.paymentMethod,
                    transactionFee: payload.transactionFee,
                  };
                  axios({
                    method: "post",
                    url: `${process.env.REACT_APP_LDOCS_API_URL}/payment/invoicePayment`,
                    data: data,
                    headers: {
                      cooljwt: payload.Token,
                    },
                  })
                    .then(async (response) => {
                      console.log("Success");
                    })
                    .catch((err) => {
                      console.log("Issue");
                    });
                }
              });
            },
          })
          .render("#paypal-button");
        setTimeout(() => {
          setButtonLoaded(true);
        }, 2000);
      });
    }
  }, [scriptLoaded]);

  return (
    <div
      style={{
        padding: 0,
        margin: 0,
        listStyle: "none",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <span
        style={{
          marginTop: "20px",
          display: buttonLoaded ? "block" : "none",
        }}
        id="paypal-button"
      ></span>
      {!buttonLoaded ? <p>Loading...</p> : "" }
    </div>
  );
};

export default App;
